import request from '@/utils/request'

export const profile = {
  // 获取基本信息
  getBasicInfo: () => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'get'
    })
  },

  // 更新基本信息
  updateBasicInfo: (data) => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'patch',
      data
    })
  },

  // 获取详细资料
  getProfile: () => {
    return request({
      url: '/api/v1/users/profile/',
      method: 'get'
    })
  },

  // 更新详细资料
  updateProfile: (data) => {
    return request({
      url: '/api/v1/users/profile/',
      method: 'patch',
      data
    })
  }
}
